export type Snippet = {
  id: string
  title: string
  language: string
  tags: string[]
  code: string
  createdAt: string
}

export type SnippetInput = {
  title: string
  language: string
  tags: string
  code: string
}

export type FilterParams = {
  language?: string
  tag?: string
}

import type { Snippet, SnippetInput, FilterParams } from './types'

const DATA_PATH = new URL('./data/snippets.jsonl', import.meta.url).pathname

const generateId = (): string => crypto.randomUUID()

export const readSnippets = async (): Promise<Snippet[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  return text
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Snippet)
}

export const writeSnippet = async (input: SnippetInput): Promise<Snippet> => {
  const snippet: Snippet = {
    id: generateId(),
    title: input.title.trim(),
    language: input.language.trim().toLowerCase(),
    tags: input.tags
      .split(',')
      .map((t) => t.trim().toLowerCase())
      .filter(Boolean),
    code: input.code,
    createdAt: new Date().toISOString(),
  }
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  const prev = exists ? await file.text() : ''
  const next = prev.endsWith('\n') || prev === '' ? prev : prev + '\n'
  await Bun.write(DATA_PATH, next + JSON.stringify(snippet) + '\n')
  return snippet
}

export const deleteSnippet = async (id: string): Promise<void> => {
  const snippets = await readSnippets()
  const remaining = snippets.filter((s) => s.id !== id)
  const content = remaining.map((s) => JSON.stringify(s)).join('\n') + (remaining.length ? '\n' : '')
  await Bun.write(DATA_PATH, content)
}

export const filterSnippets = (snippets: Snippet[], params: FilterParams): Snippet[] => {
  let result = snippets
  if (params.language) {
    result = result.filter((s) => s.language === params.language)
  }
  if (params.tag) {
    result = result.filter((s) => s.tags.includes(params.tag))
  }
  return result
}

export const getLanguages = (snippets: Snippet[]): string[] =>
  [...new Set(snippets.map((s) => s.language))].sort()

export const getTags = (snippets: Snippet[]): string[] =>
  [...new Set(snippets.flatMap((s) => s.tags))].sort()

