    h('h1', { style: styleToString(styles.heading) }, 'Code Snippets'),
    renderSnippetForm(),
    (languages.length > 0 || tags.length > 0)
      ? renderFilterBar(languages, tags, activeLanguage, activeTag)
      : h(Fragment, {}),
    snippets.length > 0
      ? h(Fragment, {},
          ...snippets.map(renderSnippetCard),
        )
      : h('div', { style: styleToString(styles.empty) }, 'No snippets yet. Add your first one above.'),
    h('script', {}, `
      document.addEventListener('click', (e) => {
        const btn = e.target.closest('[p-trigger="click:copyCode"]');
        if (btn) {
          const code = btn.getAttribute('data-code');
          navigator.clipboard.writeText(code).then(() => {
            const prev = btn.textContent;
            btn.textContent = 'Copied!';
            setTimeout(() => { btn.textContent = prev; }, 1500);
          });
        }
      });
    `),
  )

import { createSSR } from 'plaited'
import { readSnippets, writeSnippet, deleteSnippet, filterSnippets, getLanguages, getTags } from './store'
import { renderPage } from './render'
import type { SnippetInput } from './types'

const ssr = createSSR()

const buildPage = async (language?: string, tag?: string): Promise<string> => {
  const all = await readSnippets()
  const languages = getLanguages(all)
  const tags = getTags(all)
  const filtered = filterSnippets(all, { language, tag })
  const sorted = filtered.sort((a, b) => b.createdAt.localeCompare(a.createdAt))
  const tree = renderPage(sorted, languages, tags, language, tag)
  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Code Snippets</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #18181b; }
  </style>
</head>
<body>${ssr(tree)}</body>
</html>`
}

const parseForm = async (req: Request): Promise<Record<string, string>> => {
  const formData = await req.formData()
  const result: Record<string, string> = {}
  formData.forEach((value, key) => {
    result[key] = value.toString()
  })
  return result
}

const PORT = Number(process.env.PORT) || 3000

export default {
  port: PORT,
  async fetch(req: Request): Promise<Response> {
    const url = new URL(req.url)

    if (req.method === 'GET' && url.pathname === '/') {
      const language = url.searchParams.get('language') || undefined
      const tag = url.searchParams.get('tag') || undefined
      const html = await buildPage(language, tag)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    if (req.method === 'POST' && url.pathname === '/snippets') {
      const fields = await parseForm(req)
      const input: SnippetInput = {
        title: fields.title ?? '',
        language: fields.language ?? '',
        tags: fields.tags ?? '',
        code: fields.code ?? '',
      }
      if (!input.title || !input.language || !input.code) {
        return new Response('Missing required fields', { status: 400 })
      }
      await writeSnippet(input)
      return Response.redirect(url.origin + '/', 303)
    }

    if (req.method === 'POST' && url.pathname === '/snippets/delete') {
      const fields = await parseForm(req)
      const id = fields.id
      if (id) {
        await deleteSnippet(id)
      }
      const referer = req.headers.get('referer') || '/'
      return Response.redirect(referer, 303)
    }

    return new Response('Not Found', { status: 404 })
  },
}
